update "Recipe" r set instructions = v.txt
from (values
('a0000000-0000-0000-0000-000000000001'::uuid, 'מחממים שמן זית במחבת רחבה ומטגנים בצל קצוץ ופלפל אדום עד שהם מתרככים, כחמש דקות. מוסיפים עגבניות מרוסקות, כפית פפריקה, קורט כמון, מלח ופלפל, ומבשלים על אש בינונית כעשר דקות עד שהרוטב מסמיך. יוצרים גומות ברוטב ושוברים לתוכן ביצים, מכסים ומבשלים חמש עד שבע דקות עד שהחלבון מתייצב והחלמון נשאר רך. מפזרים פטרוזיליה ומגישים עם לחם טרי.'),
('a0000000-0000-0000-0000-000000000002'::uuid, 'טורפים היטב שתי ביצים עם קורט מלח ופלפל. מחממים מעט חמאה במחבת קטנה על אש בינונית, מפזרים בצל ירוק קצוץ ומטגנים שלושים שניות. מוזגים את הביצים, מפזרים גבינה צהובה מגוררת, ומבשלים עד שהתחתית מתייצבת. מקפלים לחצי ומגישים מיד.'),
('a0000000-0000-0000-0000-000000000003'::uuid, 'מערבבים בקערה קמח, אבקת אפייה, סוכר וקורט מלח. בקערה נפרדת טורפים ביצה עם חלב, ומוזגים אל היבשים עד לבלילה חלקה. מחממים מחבת עם מעט חמאה על אש בינונית נמוכה, יוצקים מצקת בלילה לכל פנקייק, ומטגנים עד שנוצרות בועות על פני השטח. הופכים ומטגנים עוד דקה עד הזהבה. מגישים עם סילאן או סירופ מייפל.'),
('a0000000-0000-0000-0000-000000000004'::uuid, 'פורסים את חזה העוף לפרוסות דקות ומתבלים במלח ופלפל. מכינים שלוש צלחות: קמח, ביצים טרופות ופירורי לחם. טובלים כל פרוסה בקמח, אחר כך בביצה ולבסוף בפירורי לחם בלחיצה קלה. מטגנים בשמן עמוק שחומם ל-180°C כשלוש דקות מכל צד עד זהוב ופריך. מניחים על נייר סופג ומגישים עם פלח לימון.'),
('a0000000-0000-0000-0000-000000000005'::uuid, 'מחממים תנור ל-200°C. מערבבים בקערה גדולה פרגיות, תפוחי אדמה חתוכים לקוביות, בצל פרוס ושיני שום, ומתבלים בשמן זית, פפריקה, מלח ופלפל. מסדרים בתבנית בשכבה אחת ואופים כארבעים דקות, תוך ערבוב באמצע, עד שהעוף עשוי ותפוחי האדמה זהובים ורכים.'),
('a0000000-0000-0000-0000-000000000006'::uuid, 'מחממים תנור ל-220°C. חוצים תפוחי אדמה לאורכם וחורצים את הצד החתוך ברשת עדינה בעזרת סכין. מערבבים עם שמן זית, שום כתוש, פפריקה ומלח, ומסדרים בתבנית כשהצד החתוך כלפי מעלה. אופים כארבעים וחמש דקות עד שהקצוות פריכים והפנים רכים.'),
('a0000000-0000-0000-0000-000000000007'::uuid, 'מסננים את הטונה ומערבבים בקערה עם ביצה, פירורי לחם, בצל קצוץ דק ופטרוזיליה, מלח ופלפל. מעצבים לקציצות שטוחות. מחממים שמן במחבת ומטגנים על אש בינונית כשלוש דקות מכל צד עד הזהבה. מגישים עם לימון או רוטב עגבניות.'),
('a0000000-0000-0000-0000-000000000008'::uuid, 'מבשלים פסטה במים מומלחים עד אל דנטה ושומרים מעט ממי הבישול. במקביל מטגנים קוביות חזה עוף עם שום במחבת עד שהן עשויות. מוסיפים שמנת מתוקה וגבינה צהובה מגוררת ומבשלים על אש נמוכה עד שהרוטב מסמיך. מערבבים את הפסטה ברוטב, מוסיפים מעט ממי הבישול לדלילות הרצויה, ומגישים.'),
('a0000000-0000-0000-0000-000000000009'::uuid, 'מערבבים קמח, שמרים ומלח, מוסיפים מים פושרים ושמן זית ולשים לבצק רך ודביק. מתפיחים מכוסה כשעה עד שהבצק מכפיל את נפחו. משטחים בתבנית משומנת, יוצרים גומות עם האצבעות, מזלפים שמן זית ומפזרים מלח גס. מחממים תנור ל-220°C ואופים כעשרים עד עשרים וחמש דקות עד שהפוקצה זהובה.'),
('a0000000-0000-0000-0000-000000000010'::uuid, 'מחממים שמן זית בסיר ומטגנים בצל קצוץ עד שקיפות. מוסיפים בטטה חתוכה לקוביות ואפונה, מערבבים דקה, ומוסיפים ציר ירקות עד לכיסוי. מביאים לרתיחה ומבשלים על אש נמוכה כעשרים דקות עד שהבטטה רכה. טוחנים בבלנדר מוט לקרם חלק, מתבלים במלח ופלפל ומגישים.'),
('a0000000-0000-0000-0000-000000000011'::uuid, 'מניחים בסיר גדול עוף שלם עם גזר, סלרי ובצל, מכסים במים ומביאים לרתיחה. מסירים את הקצף שעולה, מנמיכים את האש ומבשלים על אש נמוכה כשעה וחצי. מוציאים את העוף, מפרידים את הבשר ומחזירים לסיר. מוסיפים אטריות ומבשלים עד שהן רכות. מתבלים במלח ומגישים חם.'),
('a0000000-0000-0000-0000-000000000012'::uuid, 'מכינים בלילה דליל מקמח ומים קרים מאוד ולא מערבבים יותר מדי. חותכים ירקות לרצועות, טובלים בבלילה, ומטגנים בשמן עמוק שחומם ל-180°C עד שהציפוי פריך ובהיר. מניחים על נייר סופג ומגישים מיד עם רוטב סויה.'),
('a0000000-0000-0000-0000-000000000013'::uuid, 'מבשלים תפוחי אדמה בקליפתם עד שהם רכים, מקררים, מקלפים וחותכים לקוביות. מערבבים בקערה עם טונה מסוננת, לימון כבוש קצוץ ובצל סגול דק. מתבלים בשמן זית, מלח ופלפל ומערבבים בעדינות. מגישים בטמפרטורת החדר.'),
('a0000000-0000-0000-0000-000000000014'::uuid, 'מחממים תנור ל-220°C. חותכים תפוחי אדמה לקוביות, מערבבים עם שמן זית ומלח, ומסדרים בתבנית בשכבה אחת. קולים כשלושים וחמש עד ארבעים דקות עד פריכות וזהב. מצננים מעט ומערבבים עם חרדל, בצל ירוק קצוץ וקורט מלח. מגישים פושר.'),
('a0000000-0000-0000-0000-000000000015'::uuid, 'טוחנים במעבד מזון חומוס מבושל עם טחינה גולמית, מיץ לימון, שום וכמון, ומוסיפים מעט מים קרים עד למרקם חלק וקרמי. מתבלים במלח לפי הטעם. מורחים בצלחת, מזלפים שמן זית ומפזרים פפריקה. מגישים עם פיתה.'),
('a0000000-0000-0000-0000-000000000016'::uuid, 'קוצצים דק עגבניות, מלפפונים ובצל. מעבירים לקערה ומתבלים במיץ לימון, שמן זית, מלח ופלפל. מערבבים ומגישים טרי. אפשר להוסיף פטרוזיליה קצוצה.'),
('a0000000-0000-0000-0000-000000000017'::uuid, 'מחממים תנור ל-180°C ומשמנים תבנית. מערבבים בקערה קמח, סוכר, קקאו ואבקת אפייה. מוסיפים ביצים, שמן ומעט מים פושרים ומערבבים לבלילה אחידה. מוזגים לתבנית ואופים כשלושים וחמש עד ארבעים דקות עד שקיסם יוצא יבש. מצננים לפני הפריסה.'),
('a0000000-0000-0000-0000-000000000018'::uuid, 'מחממים תנור ל-180°C. מקרמים חמאה רכה עם סוכר חום עד תערובת אוורירית, מוסיפים ביצה ומערבבים. מוסיפים קמח ושבבי שוקולד ולשים לבצק. יוצרים כדורים, מניחים על תבנית מרופדת במרווחים, ואופים כעשר עד שתים עשרה דקות עד שהקצוות זהובים והמרכז עדיין רך. מצננים על רשת.'),
('a0000000-0000-0000-0000-000000000019'::uuid, 'מחממים תנור ל-180°C. משטחים בצק עלים ומורחים עליו ממרח תמרים בשכבה דקה. מפזרים קוקוס וקינמון, מגלגלים לגליל הדוק ופורסים לפרוסות. מסדרים על תבנית, מברישים בביצה טרופה, ואופים כעשרים עד עשרים וחמש דקות עד הזהבה.'),
('a0000000-0000-0000-0000-000000000020'::uuid, 'ממיסים שוקולד מריר על בן מארי או במיקרוגל ומצננים מעט. מפרידים ביצים, ומקציפים את החלבונים עם הסוכר לקצף יציב. מקפלים בעדינות את החלמונים לשוקולד, ואז את הקצף ואת השמנת המוקצפת. מחלקים לכוסות ומקררים לפחות שעתיים עד התייצבות.')
) as v(id, txt)
where r.id = v.id;
